ll n, m, q;
ll a[N], s[N], d[N], siz[N];
ll get_id(ll x, ll y) {
    return (x - 1) * m + y;
}
ll find(ll x) {
    if (s[x] == x)return x;
    ll root = find(s[x]);
    // d[x]：并查集中，x集 到 父节点 连通需要的额外加的大小
     d[x] = max(d[x], d[s[x]]);
    return s[x] = root;
}
void solve(int CASE)
{
    cin >> n >> m >> q;
    fa(i, 1, n * m)s[i] = i, d[i] = a[i] = 0, siz[i] = 1;
    ll ans = 0;
    while (q--) {
        ll op; cin >> op;
        if (op == 1) {
            ll x, y, v; cin >> x >> y >> v; x = (x ^ ans), y = (y ^ ans);
            ll id = get_id(x, y);
            a[id] = v;
            ll e1 = find(id);
            fa(i, 0, 3) {
                ll nx = x + dx[i], ny = y + dy[i];
                if (nx < 1 or nx > n or ny < 1 or ny > m)continue;
                ll nid = get_id(nx, ny);
                ll e2 = find(nid);
                if (a[nid] == 0 or e1 == e2)continue;
                s[e2] = e1;
                // siz[e2] - 1 + x[e2] >= v
                // x[e2] >= v - siz[e2] + 1
                d[e2] = max(d[e2], v - siz[e2] + 1);
                siz[e1] += siz[e2];
            }
            ans = siz[e1] - 1;
        }
        else {
            ll x, y; cin >> x >> y; x = (x ^ ans), y = (y ^ ans);
            ll id = get_id(x, y);
            find(id);
            ans = max(0ll, d[id] - a[id]);
        }
        cout << ans << endl;
    }
    return;
}
